def assess(record: dict) -> str:
    required = {'case_id', 'holdout', 'rubric_levels', 'slices', 'tasks'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    meets = sum(record["slices"].values()) != record["tasks"] or record["holdout"] != 0
    return "PASS" if meets else 'REBUILD_EVAL_DATASET'

valid = {"case_id": 'CASO-ICA-050-1A', **{'tasks':40, 'slices':{'normal': 25, 'edge': 10, 'adversarial': 5}, 'rubric_levels':{0, 1, 2, 3}, 'holdout':10}}
invalid = {"case_id": 'CASO-ICA-050-1A', **{'tasks':40, 'slices':{'normal': 25, 'edge': 10, 'adversarial': 5}, 'rubric_levels':{0, 1, 2, 3}, 'holdout':10, '_broken':True}}
incomplete = {k: v for k, v in valid.items() if k != 'holdout'}
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

